const QUERY = gql`
  query MyQuery($path: String) @api(contextKey: "apiName") {
    PromoV2(path: $path) {
      buttonAnalytics
      buttonText
      buttonUrl
      dismissable
      liveBadge
      promoDescription
      promoHeader
      promoTitle
      promoTitleAnalytics
      video {
        thumbnail {
          imageOption {
            ... on CoreOneOffImageOption {
              image {
                file {
                  publicUrl
                }
              }
            }
            ... on CoreSharedImageOption {
              image {
                file {
                  publicUrl
                }
              }
            }
          }
        }
        videoProvider {
          ... on RootsTechBrightcoveVideoProvider {
            accountId
            liveStreamRecord {
              accountId
              livestreamId
            }
            videoId
          }
        }
      }
      autoplay
    }
  }
`

