// Persists a boolean in a cookie — cookie presence signals the value differs from the default.
function useCookieState(cookieName: string, defaultValue = true): [boolean, (value: boolean) => void] {
  const [value, setValue] = useState(() => {
    const hasCookie = Cookies.get(cookieName)
    return hasCookie ? !defaultValue : defaultValue
  })

  useLayoutEffect(() => {
    if (value === defaultValue) {
      Cookies.remove(cookieName)
    } else {
      Cookies.set(cookieName, '1', { expires: COOKIE_EXPIRATION_DAYS })
    }
  }, [value, cookieName, defaultValue])

  return [value, setValue]
}

function useAutoCollapseOnMobile(setIsExpanded: (value: boolean) => void): void {
  const atWidth = useContainerWidth()
  const isMobile = atWidth({ default: true, lg: false })

  useEffect(() => {
    if (isMobile) {
      setIsExpanded(false)
    }
  }, [isMobile, setIsExpanded])
}

function broadcastExpanded(isExpanded: boolean): void {
  getCrossTabChannel()?.postMessage({ type: 'expand', isExpanded })
}

// Re-expands a stale collapsed state when the date reset fires. React state must be updated directly
// because useCookieState initializes from the cookie synchronously. applied.current is set on first
// detection so a user manually collapsing later doesn't re-trigger it. Skips if collapsedPref > resetDate.
function useDateResetExpand(
  resetDate: number | null,
  isExpanded: boolean,
  setIsExpanded: (value: boolean) => void,
  signedIn: boolean,
  collapsedPref: string | undefined
): void {
  const applied = useRef(false)

  useEffect(() => {
    if (applied.current || !resetDate || Date.now() < resetDate) return
    // Mark as applied immediately — prevents re-firing when the user later collapses manually.
    applied.current = true
    if (isExpanded) return
    if (collapsedPref && Number(collapsedPref) > resetDate) return
    setIsExpanded(true)
    if (signedIn) {
      deletePreference(COLLAPSED_PREFERENCE)?.catch(console.error)
    }
  }, [resetDate, isExpanded, setIsExpanded, signedIn, collapsedPref])
}

// Applies the stored collapsed preference once on login; user interactions take priority after.
function usePreferenceIsKing(
  signedIn: boolean,
  pendingSync: boolean,
  collapsedPref: string | undefined,
  setIsExpanded: (value: boolean) => void
): void {
  const applied = useRef(false)

  useEffect(() => {
    if (applied.current || !signedIn || pendingSync || !collapsedPref) return
    applied.current = true
    setIsExpanded(false)
  }, [signedIn, pendingSync, collapsedPref, setIsExpanded])
}

// On login, syncs the cookie's expand/collapse state into the preference so it persists cross-device.
// A ref guards against re-running since pendingSync (React state) stays true but sessionStorage is cleared.
function usePendingCollapsedSync(signedIn: boolean, pendingSync: boolean, isExpanded: boolean): void {
  const synced = useRef(false)

  useEffect(() => {
    if (synced.current || !signedIn || !pendingSync) return
    synced.current = true
    if (isExpanded) {
      deletePreference(COLLAPSED_PREFERENCE)?.catch(console.error)
    } else {
      setPreference(COLLAPSED_PREFERENCE, Date.now())?.catch(console.error)
    }
    sessionStorage.removeItem(COLLAPSED_SESSION_FLAG)
  }, [signedIn, pendingSync, isExpanded])
}

type CrossTabHandlers = {
  onDismiss?: () => void
  onExpand?: (isExpanded: boolean) => void
}

// Mirrors dismiss and expand/collapse actions from other tabs via BroadcastChannel.
function useCrossTabSync({ onDismiss, onExpand }: CrossTabHandlers): void {
  useEffect(() => {
    const channel = getCrossTabChannel()
    if (!channel) return undefined

    const onMessage = (event: MessageEvent): void => {
      const { data } = event
      if (!data || typeof data !== 'object') return
      if (data.type === 'dismiss' && onDismiss) onDismiss()
      else if (data.type === 'expand' && onExpand) onExpand(data.isExpanded ?? true)
    }

    channel.addEventListener('message', onMessage)
    return () => channel.removeEventListener('message', onMessage)
  }, [onDismiss, onExpand])
}

type PromoDataResult = {
  loading: boolean
  error: unknown
  data: { PromoV2: PromoV2Data } | undefined
  hasVideo: boolean
}

function usePromoData(url?: string, site?: string): PromoDataResult {
  const { loading, error, data } = useQuery<{ PromoV2: PromoV2Data }>(QUERY, {
    variables: { path: `/${url}` },
    context: { apiName: `${site}:custom` },
    skip: !url || !site,
  })

  const hasVideo = useMemo(() => !!data?.PromoV2?.video?.videoProvider, [data])

  return { loading, error, data, hasVideo }
}

function useTrackInitialLoad(
  url: string | undefined,
  hasVideo: boolean,
  isExpanded: boolean,
  data: unknown,
  loading: boolean,
  error: unknown,
  hasTrackedInitialLoad: React.MutableRefObject<boolean>
): void {
  useEffect(() => {
    if (!data || loading || error || !url || hasTrackedInitialLoad.current) return
    const linkName = hasVideo ? `Promo:${url}:${isExpanded ? 'Open' : 'Closed'}` : `Promo:${url}`
    trackEvent({ event_name: 'click_action', link_name: linkName })
    hasTrackedInitialLoad.current = true
  }, [data, loading, error, url, hasVideo, isExpanded, hasTrackedInitialLoad])
}

function useTrackExpandCollapse(
  url: string | undefined,
  hasVideo: boolean,
  isExpanded: boolean,
  hasTrackedInitialLoad: React.MutableRefObject<boolean>
): void {
  useEffect(() => {
    if (!hasVideo || !hasTrackedInitialLoad.current || !url) return
    trackEvent({ event_name: 'click_action', link_name: `Promo:${url}:${isExpanded ? 'Open' : 'Closed'}` })
  }, [isExpanded, hasVideo, url, hasTrackedInitialLoad])
}

function usePromoAnalytics(
  url: string | undefined,
  hasVideo: boolean,
  isExpanded: boolean,
  data: unknown,
  loading: boolean,
  error: unknown
): void {
  const hasTrackedInitialLoad = useRef(false)
  useTrackInitialLoad(url, hasVideo, isExpanded, data, loading, error, hasTrackedInitialLoad)
  useTrackExpandCollapse(url, hasVideo, isExpanded, hasTrackedInitialLoad)
}

// Keeps --rootstech-promo-height in sync so other elements (e.g. chatbot) can offset themselves.
function usePromoHeightVariable(promoRef: React.RefObject<HTMLDivElement>, isExpanded: boolean): void {
  const updateHeight = useCallback(() => {
    if (!promoRef.current) return
    document.documentElement.style.setProperty('--rootstech-promo-height', `${promoRef.current.clientHeight}px`)
  }, [promoRef])

  useResizeObserver(promoRef, updateHeight)

  useEffect(() => {
    updateHeight()
  }, [isExpanded, updateHeight])

  useEffect(() => {
    return () => {
      document.documentElement.style.setProperty('--rootstech-promo-height', '0px')
    }
  }, [])
}

function createPortalContainer(containerId: string): HTMLDivElement | null {
  if (typeof window === 'undefined') return null

  const existing = document.getElementById(containerId) as HTMLDivElement | null
  if (existing) return existing

  const pageHeader = document.querySelector('header')
  if (!pageHeader?.parentNode) return null

  const div = document.createElement('div')
  div.id = containerId
  pageHeader.parentNode.insertBefore(div, pageHeader)
  return div
}

function removePortalContainer(container: HTMLDivElement | null): void {
  container?.parentNode?.removeChild(container)
}

// Mounts the banner portal container before the page header; reuses existing node to survive StrictMode double-invoke.
function usePortalContainer(): HTMLDivElement | null {
  const [container, setContainer] = useState<HTMLDivElement | null>(null)

  useEffect(() => {
    const alreadyExists = !!document.getElementById(BANNER_PORTAL_ID)
    const c = createPortalContainer(BANNER_PORTAL_ID)
    setContainer(c)
    return () => {
      if (!alreadyExists) removePortalContainer(c)
    }
  }, [])

  return container
}

type SetOpenFunction = (state: boolean) => void

// Cookie-persisted expand/collapse state; syncs with user preference; broadcasts changes to other
// tabs and auto-collapses on mobile.
// Returns [isExpanded, setAndBroadcast, setSilent] where setSilent skips the broadcast (used for
// receiving cross-tab messages to avoid echo loops).
function useExpanded(): [boolean, SetOpenFunction, SetOpenFunction] {
  const { signedIn } = useUser()
  const collapsedPref = usePreference(COLLAPSED_PREFERENCE)
  const [isExpanded, setIsExpanded] = useCookieState(EXPANDED_COOKIE, true)
  const { config: dateResetConfig } = useFeatureFlag<RootstechPromoDateFlag>(PROMO_DATE_FLAG)
  const resetDate = dateResetConfig?.date ? Date.parse(dateResetConfig.date) || null : null

  // Read session flag once at mount — set when a logged-out user changed expand/collapse state,
  // so we know to sync the cookie value into their preference on next login.
  const [pendingSync] = useState(() => sessionStorage.getItem(COLLAPSED_SESSION_FLAG) === '1')

  useAutoCollapseOnMobile(setIsExpanded)
  useDateResetExpand(resetDate, isExpanded, setIsExpanded, signedIn, collapsedPref)
  usePreferenceIsKing(signedIn, pendingSync, collapsedPref, setIsExpanded)
  usePendingCollapsedSync(signedIn, pendingSync, isExpanded)

  const setExpandedState = useCallback(
    (state: boolean) => {
      setIsExpanded(state)
      if (signedIn) {
        if (state) {
          deletePreference(COLLAPSED_PREFERENCE)?.catch(console.error)
        } else {
          setPreference(COLLAPSED_PREFERENCE, Date.now())?.catch(console.error)
        }
      } else {
        sessionStorage.setItem(COLLAPSED_SESSION_FLAG, '1')
      }
    },
    [signedIn, setIsExpanded]
  )

  const setExpandedAndBroadcast = useCallback(
    (state: boolean) => {
      setExpandedState(state)
      broadcastExpanded(state)
    },
    [setExpandedState]
  )

  return [isExpanded, setExpandedAndBroadcast, setExpandedState]
}

type PromoOverlayProps = {
  data: { PromoV2: PromoV2Data }
  open: boolean
  setOpen: SetOpenFunction
  hide: () => void
  controlsId: string
}

const PromoOverlay = memo(({ data, open, setOpen, hide, controlsId }: PromoOverlayProps) => {
  const { t } = useTranslation()
  const { PromoV2 } = data
  const videoProvider = PromoV2?.video?.videoProvider
  const thumbnailUrl = PromoV2?.video?.thumbnail?.imageOption?.image?.file?.publicUrl || ''
  const promoContentRef = useRef<HTMLDivElement>(null)

  usePromoHeightVariable(promoContentRef, open)

  // Only render Brightcove videos
  const videoChild =
    videoProvider &&
    '__typename' in videoProvider &&
    // eslint-disable-next-line no-underscore-dangle -- __typename comes from brightspot's GraphQL and is necessary for type narrowing
    videoProvider.__typename === 'RootsTechBrightcoveVideoProvider' ? (
      <Video
        videoProvider={{
          __typename: 'RootsTechBrightcoveVideoProvider',
          accountId: videoProvider?.accountId || undefined,
          videoId: videoProvider.videoId || undefined,
        }}
        thumbnailUrl={thumbnailUrl}
        title={PromoV2?.promoTitle}
        autoplay={PromoV2?.autoplay || false}
      />
    ) : null

  return (
    <Elevation
      z={1}
      className={overlayCss}
      ref={promoContentRef}
      data-testid="rootstech-promo"
      data-closed={boolAttr(!open)}
    >
      <Expander open={open} setOpen={setOpen} ariaControlsId={controlsId}>
        <Theme theme="night" className={headerCss}>
          <MarginBox marginY="nano" marginX="xs">
            <Row alignY="middle">
              <GenericHeading
                as="div"
                tabIndex={0}
                role="button"
                size="H6"
                growX
                onClick={() => {
                  setOpen(!open)
                  PromoV2?.promoTitleAnalytics &&
                    trackEvent({
                      event_name: 'click_action',
                      link_name: `${PromoV2.promoTitleAnalytics}-${open ? 'collapse' : 'expand'}`,
                    })
                }}
                aria-controls={controlsId}
                aria-expanded={open}
              >
                {PromoV2?.promoTitle}
              </GenericHeading>
              <IconButton
                Icon={ArrowCaret}
                color="gray"
                iconDirection={open ? 'down' : 'up'}
                aria-controls={controlsId}
                linkName={`${PromoV2?.promoTitleAnalytics}-${open ? 'collapse' : 'expand'}`}
                aria-expanded={open}
                onClick={() => setOpen(!open)}
                title={open ? t('common-ui:close.action') : t('common-ui:open.action')}
              />
              <IconButton
                Icon={MenuClose}
                color="gray"
                onClick={hide}
                linkName={`${PromoV2?.promoTitleAnalytics}-dismiss`}
                title={t('common-ui:remove.action')}
              />
            </Row>
          </MarginBox>
        </Theme>
        <Theme theme="day">
          <ExpanderContent>
            <Suspense fallback={null}>{open && videoChild}</Suspense>
            <MarginBox marginX="xs" marginY="xs">
              <H2 size="H5">{PromoV2?.promoHeader}</H2>
              <Paragraph size="sm">{PromoV2?.promoDescription}</Paragraph>
              <Separator size="sm" />
              <Row alignX="end">
                {/* @ts-expect-error -- grandfathered from before strict mode was adopted. */}
                <Button
                  color="gray"
                  emphasis="high"
                  to={PromoV2?.buttonUrl}
                  linkName={PromoV2?.buttonAnalytics}
                  target="_blank"
                >
                  {PromoV2?.buttonText}
                </Button>
              </Row>
            </MarginBox>
          </ExpanderContent>
        </Theme>
      </Expander>
    </Elevation>
  )
})

type PromoBannerProps = {
  data: { PromoV2: PromoV2Data }
  hide: () => void
}

const PromoBanner = memo(({ data, hide }: PromoBannerProps) => {
  const { t } = useTranslation()
  const { PromoV2: promoData } = data
  const container = usePortalContainer()
  const atWidth = useContainerWidth()

  if (!container) return null

  return createPortal(
    <LayoutBand className={bannerCss} data-testid="rootstech-promo-banner" marginY="nano">
      <Row alignY="middle" alignX="center" wrap>
        {promoData?.liveBadge && <span className={liveBadgeCss}>{promoData.liveBadge}</span>}
        <Paragraph centered={atWidth({ default: true, md: false })}>
          {promoData?.promoTitle || '{missing title}'}
        </Paragraph>
        <Row alignX="center" alignY="middle">
          {promoData?.buttonText && promoData?.buttonUrl && (
            <Button
              color="gray"
              emphasis="high"
              to={promoData.buttonUrl}
              linkName={promoData.buttonAnalytics}
              target="_blank"
            >
              {promoData.buttonText}
            </Button>
          )}
          {promoData?.dismissable && (
            <Button color="gray" emphasis="low" onClick={hide} linkName={`${promoData.buttonAnalytics}-dismiss`}>
              {t('common-ui:dismiss.action', 'Dismiss')}
            </Button>
          )}
        </Row>
      </Row>
    </LayoutBand>,
    container
  )
})

type PromoContentProps = {
  isOn: boolean
  config?: RootstechPromoConfig
  hide: () => void
}

const PromoContent = memo(({ isOn, config, hide }: PromoContentProps) => {
  const { url, site } = config || {}
  const [open, setOpen, setOpenSilent] = useExpanded()
  const controlsId = useRandomId()

  useCrossTabSync({ onDismiss: hide, onExpand: setOpenSilent })

  const { loading, error, data, hasVideo } = usePromoData(url, site)

  usePromoAnalytics(url, hasVideo, open, data, loading, error)

  if (!(isOn && url && site) || loading || error || !data) {
    return null
  }

  if (!hasVideo) {
    return <PromoBanner data={data} hide={hide} />
  }

  return (
    <ErrorBoundary fallback={null}>
      <PromoOverlay data={data} open={open} setOpen={setOpen} hide={hide} controlsId={controlsId} />
    </ErrorBoundary>
  )
})

const RootstechPromo = memo(({ hide }: { hide: () => void }) => {
  const bandwidth = useBandwidth()
  const dateRef = useRef(new Date())
  const promoFlag = useFeatureFlag<{ treatment: string; config?: RootstechPromoConfig }>(PROMO_FLAG, {
    appName,
    // @ts-expect-error -- SplitIO.AttributeType doesn't include Date, but the SDK handles it correctly at runtime
    date: dateRef.current,
    bandwidth,
  })
  if (!promoFlag.isOn) return null

  return (
    <div className={positionBoxCss}>
      <Suspense fallback={null}>
        {/* @ts-expect-error -- grandfathered from before strict mode was adopted. */}
        <BrightspotProvider sites={[promoFlag.config?.site]} hasCustomContent>
          <PromoContent isOn={promoFlag.isOn} config={promoFlag.config} hide={hide} />
        </BrightspotProvider>
      </Suspense>
    </div>
  )
})

export default RootstechPromo
