import { useEffect, useState } from 'react'
import { useFeatureFlag } from '@fs/zion-flags'
import { useSyncedRef } from '@fs/zion-frontend-friends'
import { trackEvent } from '@fs/zion-analytics'

function computeAverage(arr) {
  const sum = arr.reduce((acc, val) => acc + val, 0)
  const average = sum / arr.length
  return Math.round(average * 100) / 100
}

const smallImage = {
  size: 900,
  url: 'https://edge.fscdn.org/assets/docs/fs_logo_favicon_sq.png?cacheBuster=',
}
const medImage = {
  size: 2662,
  url: 'https://edge.fscdn.org/assets/static/media/Frame.d1cda7a04380b4ce6bf0.png?cacheBuster=',
}
const largeImage = {
  size: 35034,
  url: 'https://edge.fscdn.org/assets/static/media/familysearch-tree.dc22204d2135c739e39d0af7d519e182.svg?cacheBuster=',
}

const measureDownloadSpeed = (maxImageLoadLength, downloadInfo) => {
  return new Promise((resolve, reject) => {
    const download = new Image()
    const startTime = Date.now()
    download.src = downloadInfo.url + startTime

    const timeout = setTimeout(() => {
      reject(new Error('Download Timeout'))
    }, maxImageLoadLength)

    download.onload = () => {
      clearTimeout(timeout)
      const endTime = new Date().getTime()
      const duration = (endTime - startTime) / 1000
      const bitsLoaded = downloadInfo.size * 8
      const speedBps = (bitsLoaded / duration).toFixed(2)
      const speedKbps = (speedBps / 1024).toFixed(2)
      const speedMbps = (speedKbps / 1024).toFixed(2)
      resolve(Number(speedMbps))
    }
  })
}

const checkCache = () => {
  try {
    const minutesToCache = 30
    const cache = localStorage.getItem('fs-user-bandwidth')
    const currentTime = Date.now()
    if (cache) {
      const data = JSON.parse(cache)
      if (data && data?.timeOfCache && currentTime - data.timeOfCache < 1000 * 60 * minutesToCache) {
        return Number(data?.value) || null
      }
    }
    return null
  } catch (err) {
    console.error('Error with Local Cache: ', err)
    return null
  }
}

const fetchChromeBandwidth = () => {
  if (typeof navigator === 'undefined') return -1
  if (!navigator.connection) return -1
  return navigator.connection.downlink
}

const fetchCustomBandwidth = async () => {
  const downloadSize = 'md' // Set to either 'sm', 'md', or 'lg' to test different image sizes
  let downloadInfo = smallImage
  if (downloadSize === 'md') {
    downloadInfo = medImage
  } else if (downloadSize === 'lg') {
    downloadInfo = largeImage
  }

  const downloadSpeedList = []
  const numTests = 2
  const maxImageLoadLength = 2000

  for (let i = 0; i < numTests; i++) {
    const downloadSpeedPromise = measureDownloadSpeed(maxImageLoadLength, downloadInfo)
    downloadSpeedList.push(downloadSpeedPromise)
  }
  try {
    const speeds = await Promise.all(downloadSpeedList)
    const averageSpeed = computeAverage(speeds)
    return averageSpeed || -1 // Return -1 if Average Speed is 0
    // Loading of Image Timed Out
  } catch (error) {
    return -1
  }
}

// exported only for tests
export const normalizeData = ({ chromeScore, customScore }) => {
  // Automatically give worst score if custom algorithm timed out
  if (customScore < 0) {
    return 0
  }

  const normalChromeData = Math.max(Math.min(Math.round(chromeScore * 10), 100), 0) // Chrome now on a scale of 0 - 100
  let normalCustomData = Math.max(Math.min(Math.round(customScore * 100), 100), 0) // Custom now on a scale of 0 - 100

  // Automatically give best score if custom algorithm is higher than 75
  if (normalCustomData >= 75) {
    return 100
  }

  // Curve normalCustomData slightly due to it underestimating on average
  normalCustomData = Math.min(Math.round(normalCustomData * 1.5), 100)

  // If Network Information API not supported due to browser, only return custom data
  if (chromeScore === -1) {
    // Score is curved again as the algorithm favors Chrome users generally
    return Math.min(Math.round(normalCustomData * 1.5), 100)
  }

  // Return average of two values slightly weighted towards chrome data
  return Math.round(normalChromeData * 0.6 + normalCustomData * 0.4)
}

export const useBandwidth = ({ skipCache = false } = {}) => {
  const [bandwidth, setBandwidth] = useState('unknown')
  const bandwidthCheck = useFeatureFlag('frontier_zion_bandwidth')
  const bandwidthCategory = useFeatureFlag('frontier_zion_bandwidthCategories', { bandwidth })

  const skipCacheRef = useSyncedRef(skipCache)

  useEffect(() => {
    let cancelled = false
    let timeoutId = 0
    const getBandwidthInfo = async () => {
      if (bandwidthCheck.isOn) {
        try {
          // Return Immediately if Cache Hits
          const cachedValue = checkCache()
          if (cachedValue !== null && !skipCacheRef.current && !cancelled) {
            setBandwidth(cachedValue)
            return
          }

          // Obtain Chrome Data
          const chromeScore = fetchChromeBandwidth()

          // Obtain Custom Bandwidth Data with Delay
          timeoutId = setTimeout(async () => {
            const customScore = await fetchCustomBandwidth()
            const normalizedData = normalizeData({ chromeScore, customScore })
            setBandwidth(normalizedData)

            // Update Cache if Cache Miss
            const cache = {
              value: normalizedData,
              timeOfCache: Date.now(),
            }
            localStorage.setItem('fs-user-bandwidth', JSON.stringify(cache))
          }, 750)
        } catch (e) {
          console.error('Error fetching bandwidth data: ', e)
        }
      }
    }
    getBandwidthInfo()

    // Cancel timeout etc. when hook is cancelled by React during async actions
    return () => {
      cancelled = true
      clearTimeout(timeoutId)
    }
  }, [bandwidthCheck.isOn, skipCacheRef])

  useEffect(() => {
    if (bandwidthCategory.treatment !== 'unknown') {
      trackEvent({
        event_name: 'click_action',
        link_name: 'Bandwidth Check',
        lowBandwidth_Detection: bandwidthCategory.treatment, // Sends Analytics the string configured in Split based on bandwidth level.
      })
    }
  }, [bandwidthCategory.treatment])
  return bandwidth === 'unknown' ? 'unknown' : bandwidthCategory.treatment
}

export default useBandwidth
